var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"후아암-","JPN":"ふああ……","ENG":"*Yawn*","TWN":"哈啊，好睏——"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"우웅…","JPN":"うーん……","ENG":"Mm...","TWN":"呃嗯……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"으휴, 이 꼬맹이. 아침에 눈도 제대로 못 뜨는 거봐.","JPN":"ったく、まだ寝ぼけてるの？","ENG":"Ugh, look at this kid. She can't even wake up in the morning.","TWN":"哈，臭小鬼。一早連眼睛都睜不開。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"밤늦게까지 사각사각대며 그림이나 그려대더니. 역시 피곤한 거지?","JPN":"夜遅くまで絵を描いてると思ったら……まだ疲れが取れてないんだろう？","ENG":"You stayed up late at night scribbling drawings. You're still tired, aren't you?","TWN":"熬夜畫畫到這麼晚，果然累了吧？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그럼요. 피곤한 건 하루를 열심히 보냈다는 뜻이니까요.","JPN":"疲れてるということは、一日頑張った証拠です。","ENG":"Yup. Because being tired means that you had an eventful day.","TWN":"疲憊就表示度過了充實的一天。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그날 있었던 일을 제대로 기록해두는 건, 엄청 어-엄청 중요한 일이라구요.","JPN":"そしてそんな一日の出来事をちゃんと記録として残すのは、とーっても大事なことなんです。","ENG":"And recording what happened that day is very, very important.","TWN":"並且好好記錄那天發生的事情，是非常、非常重要的事。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"특히 패리의 이 복슬복슬을 표현하려고 제가 얼마나 노력했는데요.","JPN":"特に、パリーのこのふわもこ感を表現するためにすごく苦労したんですよ？","ENG":"I even spent a lot of time trying to express your fluffiness.","TWN":"為了特別表現悖悖的柔軟，我可是下了不少功夫呢。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이게 나라고? 당연히 침식체를 그려 놓은 줄 알았더니.","JPN":"これが私？　侵食体だと思ってた。","ENG":"This is me? I was sure you were drawing a C.O.","TWN":"這是我嗎？我還以為是畫了侵蝕體呢。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"우- 너무해. 열심히 그렸는데!","JPN":"ううーひどい！　頑張って描いたのに！","ENG":"Seriously? But I worked so hard on it!","TWN":"嗚——，太過分了。人家畫得這麼認真！"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐, 계속 보니 닮은 것 같기도 하고-","JPN":"まあ、よく見たら似てる……かもね。","ENG":"Well, the more I look at it, the more it does seem like me...","TWN":"嗯，看久了好像確實有點像……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"마음에 들면 돌아갈 때 선물로 줄게요.","JPN":"気に入りました？　じゃあプレゼントしますから、帰る時に持ってってくださいね。","ENG":"I'll give it to you as a present if you like it.","TWN":"如果你喜歡，回去的時候我會送給你～"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…기왕이면 나중에 새로 그려줘. 제대로 모델도 서줄 테니까.","JPN":"……どうせなら描き直して。あとでちゃんとモデルもやるから。","ENG":"...How about you draw me again later. I'll even pose for you.","TWN":"……既然如此，以後重新畫吧。我會好好當模特的。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"패리는 은근히 욕심쟁이네요. 알겠어요.","JPN":"パリーってば意外とこだわるタイプなんですね。","ENG":"I didn't know you were that ambitious. But all right.","TWN":"悖悖還真是個貪心鬼啊。知道啦。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"여기예요.","JPN":"ここです。","ENG":"This is it.","TWN":"在這裡了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이 문을 넘어가면, 안뜰로 통하는 길이 나올 거예요.","JPN":"この扉を通れば、中庭に繋がる道が出ます。","ENG":"Beyond this door is the passageway that leads to the inner yard.","TWN":"穿過這扇門，就是通往內院的路。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"역시 여기도 덩굴들이 입구를 막고 있네.","JPN":"やっぱり、ここもツタで塞がっている……","ENG":"The vines are blocking the entrance again.","TWN":"果然這裡的入口也被藤蔓擋住了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"걱정 말아요. 이번에도 제가 부탁해볼…","JPN":"大丈夫です。今回も私がお願いして……","ENG":"Don't worry. I'll ask them to move again–","TWN":"別擔心。這次也交給我吧……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어…?","JPN":"あれ……？","ENG":"Huh...?","TWN":"呃……？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"왜 그래?","JPN":"どうしたの？","ENG":"What's wrong?","TWN":"怎麼了？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"안 움직여요. 덩굴들한테 제 목소리가 닿지 않나 봐요.","JPN":"動きません。ツタに私の声が届いてないみたいです。","ENG":"They won't move. I don't think my voice is reaching the vines.","TWN":"動不了了。我的聲音好像傳不到藤蔓那裡。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네 능력이 안 통한다고?","JPN":"能力が通じない？","ENG":"Your abilities aren't working on them?","TWN":"你的能力不起作用嗎？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이상하네요. 이렇게 가까이 있는데, 엄청 멀리 있는 것처럼 느껴져요.","JPN":"変ですね。こんなにも近くにいるのに、すごく遠く感じるんです。","ENG":"That's weird. I'm so close to them, but I feel like they're very far away.","TWN":"真奇怪。明明這麼近，卻感覺像是很遠一樣。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그러고 보니 이상하군.","JPN":"言われてみれば何かおかしい。","ENG":"That is strange.","TWN":"……這樣看來是蠻奇怪的。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이렇게 바람이 부는데도 울타리 너머의 잎은 흔들리지 않다니. 이건 마치…","JPN":"こんなに風が吹いてるのに、柵の向こうの葉っぱは揺れてない。まるで……","ENG":"I can feel the wind blowing, but the leaves behind the fence aren't even swaying. It's as if...","TWN":"風這麼大，籬笆外的葉子卻一動不動。這簡直就像是……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"꼭 저희 앞에 눈에 안 보이는 벽이 있는 것 같아요.","JPN":"目に見えない壁があるみたいです。","ENG":"It's like there's an invisible wall in front of us.","TWN":"像是我們面前有一堵看不見的牆。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};